SELECT
    count(*)
FROM ad_user_mst
WHERE user_id != #{userId}
    AND user_email_addr = #{userEmailAddr}
    AND del_yn = 'N'

mapper.update:

UPDATE ad_user_mst
SET user_pwd = #{userPwd}
  , user_bf_pwd = #{userBfPwd}
  , user_pwd_last_upd_date = SYSDATE
WHERE user_id = #{userId}

    UPDATE ad_user_mst
    SET user_nm = #{userNm}
      , user_pwd = #{userPwd}
      , user_pwd_last_upd_date = SYSDATE
      , user_bf_pwd = #{userNowPwd}
	  , user_co_fg_cd = #{userCoFgCd}
	  , user_email_addr = #{userEmailAddr}
	  , stm_last_upd_date = SYSDATE
	  , init_menu_id = #{initMenuId}
    WHERE user_id = #{userId}

mapper.select:
SELECT T.* FROM ( SELECT seq_id, stm_cd, alrm_nm, alrm_note, alrm_cts, alrm_lvl_cd, alrm_tgt_addr, TO_CHAR(stm_fir_reg_date,'YYYY.MM.DD HH24:MI:SS') stm_fir_reg_date FROM ad_stm_alrm_hst WHERE 1 = 1 AND stm_fir_reg_date > ( SELECT CASE WHEN alrm_last_conf_date IS NULL THEN TO_DATE('20190101', 'YYYYMMDD') ELSE SYSDATE - ( SELECT comm_cd FROM ad_comm_cd WHERE comm_grp_cd = 'ALARM_EXPIR_DUR' ) END sel_dt FROM ad_user_mst WHERE user_id = #{userId} ) AND stm_cd = ( SELECT CASE WHEN stm_cd = '0005' THEN ( SELECT '0005' FROM ad_user_autr_map WHERE user_id = #{userId} AND autr_id = '0001' ) ELSE stm_cd END FROM dual )
AND alrm_lvl_cd = #{alrmLvlCd}
order by stm_fir_reg_date desc ) T WHERE ROWNUM <= (SELECT comm_cd FROM ad_comm_cd WHERE comm_grp_cd = 'ALRAM_MAX_ROW')

mapper.update:

UPDATE ad_user_mst
SET alrm_last_conf_date = sysdate
  , stm_last_upd_date = sysdate
  , stm_last_upd_user_id = #{userId}
WHERE user_id = #{userId}

mapper.insert:

